def get_ram_gb():
    """Returns available RAM in GB."""
    try:
        if platform.system() == "Linux":
            with open("/proc/meminfo", "r") as f:
                for line in f:
                    if "MemTotal" in line:
                        return int(line.split()[1]) / (1024 * 1024)
        elif platform.system() == "Darwin":
            res = subprocess.run(["sysctl", "hw.memsize"], capture_output=True, text=True)
            return int(res.stdout.split(":")[1].strip()) / (1024**3)
    except Exception as e:
        logging.error(f"Erro ao obter RAM: {e}")
        pass
    return 4.0 # Default fallback


def has_gpu():
    """Detects GPU presence using multiple methods."""
    try:
        # NVIDIA
        res = subprocess.run(["nvidia-smi"], capture_output=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        if res.returncode == 0:
            return True

        # AMD
        res = subprocess.run(["rocminfo"], capture_output=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        if res.returncode == 0:
            return True

        # Intel
        res = subprocess.run(["intel_gpu_top"], capture_output=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        if res.returncode == 0:
            return True

    except Exception as e:
        logging.error(f"Erro ao detectar GPU: {e}")
    return False


def get_disk_gb():
    """Returns available disk space in GB."""
    try:
        stat = os.statvfs('/')
        return (stat.f_bavail * stat.f_frsize) / (1024**3)
    except Exception as e:
        logging.error(f"Erro ao obter espaço em disco: {e}")
        return 10.0


def detect_tier(ram_gb, gpu_available):
    """Categorizes system into performance tiers for model selection."""
    if ram_gb < 8:
        return "LOW", "llama3.2:3b"
    elif ram_gb < 16:
        return "MID", "llama3.1:8b"
    elif gpu_available:
        return "HIGH", "llama3.1:8b" # Default to 8B even on HIGH for speed, but can go higher
    else:
        return "MID", "llama3.1:8b"


def main():
    try:
        ram = get_ram_gb()
        gpu = has_gpu()
        cores = multiprocessing.cpu_count()
        disk = get_disk_gb()
        os_name = platform.system()
        arch = platform.machine()

        tier, model = detect_tier(ram, gpu)

        status = {
            "os": os_name,
            "arch": arch,
            "ram_gb": round(ram, 2),
            "cores": cores,
            "gpu": gpu,
            "disk_gb": round(disk, 2),
            "tier": tier,
            "recommended_model": model,
            "capable": ram >= 8 and disk >= 10
        }

        print(json.dumps(status, indent=2))
    except Exception as e:
        logging.critical(f"Erro crítico durante execução: {e}")
        sys.exit(1)

if __name__ == "__main__":
    main()

