import sys

class MemoryManager:
    def __init__(self, size=1024):
        self.total_memory = size
        self.allocated = {}
        self.available = size

    def allocate(self, process_id, size):
        if size > self.available:
            raise MemoryError("Memória insuficiente")

        self.allocated[process_id] = size
        self.available -= size
        return True

    def deallocate(self, process_id):
        if process_id not in self.allocated:
            raise KeyError("Processo não encontrado")

        self.available += self.allocated[process_id]
        del self.allocated[process_id]
        return True

    def get_status(self):
        return {
            'total_memory': self.total_memory,
            'available': self.available,
            'allocated': self.allocated
        }

