MemoryCategory = Literal["preferences", "facts", "recurrent_tasks"]

@dataclass
class MemoryConfig:
    max_items_per_category: int = 20
    backup_on_save: bool = True

class LongTermMemory:
    """
    Persistent long-term memory storage for ARKANIS V3.
    Stores and retrieves user preferences, important facts, and recurring tasks.
    """
    def __init__(self, config: MemoryConfig = MemoryConfig()):
        self._lock = threading.Lock()
        self.data: Dict[MemoryCategory, List[str]] = {
            "preferences": [],
            "facts": [],
            "recurrent_tasks": []
        }
        self.config = config
        self._load()

    def _ensure_dir(self) -> None:
        MEM_FILE.parent.mkdir(parents=True, exist_ok=True)

    def _load(self) -> None:
        with self._lock:
            if MEM_FILE.exists():
                try:
                    with open(MEM_FILE, "r", encoding="utf-8") as f:
                        loaded_data = json.load(f)
                        # Validate and merge data
                        for category in self.data.keys():
                            if category in loaded_data and isinstance(loaded_data[category], list):
                                self.data[category] = [str(item) for item in loaded_data[category] if item]
                except Exception as e:
                    logger.error(f"Failed to load long term memory: {e}", exc_info=True)

    def _save(self) -> None:
        self._ensure_dir()
        with self._lock:
            try:
                # Create backup if enabled
                if self.config.backup_on_save and MEM_FILE.exists():
                    backup_path = MEM_FILE.with_suffix(f".bak.{int(time.time())}")
                    shutil.copy2(MEM_FILE, backup_path)

                with open(MEM_FILE, "w", encoding="utf-8") as f:
                    json.dump(self.data, f, indent=4, ensure_ascii=False)
            except Exception as e:
                logger.error(f"Failed to save long term memory: {e}", exc_info=True)

    def add_memory(self, category: MemoryCategory, content: str) -> bool:
        """Add a new memory to a category, preventing exact duplicates."""
        if category not in self.data:
            return False

        content_clean = content.strip()
        if not content_clean:
            return False

        with self._lock:
            # Prevent exact duplicate
            if content_clean in self.data[category]:
                return True

            self.data[category].append(content_clean)
            # Enforce size limit by popping oldest
            if len(self.data[category]) > self.config.max_items_per_category:
                self.data[category].pop(0)

        self._save()
        return True

    def get_formatted_memory(self) -> str:
        """Returns the long-term memory formatted for the LLM context."""
        with self._lock:
            sections = []

            if self.data["preferences"]:
                sections.append("[PREFERÊNCIAS DO USUÁRIO]\n" + "\n".join(f"- {p}" for p in self.data["preferences"]))

            if self.data["facts"]:
                sections.append("[FATOS IMPORTANTES]\n" + "\n".join(f"- {f}" for p in self.data["facts"]))

            if self.data["recurrent_tasks"]:
                sections.append("[TAREFAS RECORRENTES]\n" + "\n".join(f"- {t}" for p in self.data["recurrent_tasks"]))

            return "\n\n".join(sections) if sections else ""

